def is_valid_ipv4(ip_address):
    """
    Verifica si la dirección IP dada es una dirección IPv4 válida.
    :param ip_address: cadena, la dirección IP a verificar
    :return: bool, True si la dirección IP es válida, False en caso contrario
    >>> IpUtil.is_valid_ipv4('192.168.0.123')
    True
    >>> IpUtil.is_valid_ipv4('256.0.0.0')
    False

    """
    if not isinstance(ip_address, str):
        return False

    parts = ip_address.split('.')

    if len(parts) != 4:
        return False

    for part in parts:
        if not part:
            return False

        if not part.isdigit():
            return False

        if part[0] == '0' and len(part) > 1:
            return False

        num = int(part)
        if num < 0 or num > 255:
            return False

    return True

def update(self, predicted_labels, true_labels):
    """
    Actualiza el número de las cuatro muestras (verdaderos_positivos, falsos_positivos, falsos_negativos, verdaderos_negativos)
    :param predicted_labels: lista, resultados predichos
    :param true_labels: lista, etiquetas verdaderas
    :return: Ninguno, cambia el número de muestras correspondientes
    >>> mc = MetricsCalculator()
    >>> mc.update([1, 1, 0, 0], [1, 0, 0, 1])
    (self.true_positives, self.false_positives, self.false_negatives, self.true_negatives) = (1, 1, 1, 1)
    """
    for predicted, true in zip(predicted_labels, true_labels):
        if predicted == 1 and true == 1:
            self.true_positives += 1
        elif predicted == 1 and true == 0:
            self.false_positives += 1
        elif predicted == 0 and true == 1:
            self.false_negatives += 1
        elif predicted == 0 and true == 0:
            self.true_negatives += 1

def previous_song(self):
    """
    Cambia a la canción anterior en la lista de reproducción.
    :return: True si se cambió a la canción anterior, False si no había canción anterior.
    >>> musicPlayer = MusicPlayer()
    >>> musicPlayer.playlist = ["canción1", "canción2"]
    >>> musicPlayer.current_song = "canción2"
    >>> musicPlayer.previous_song()
    True

    """
    if not hasattr(self, 'playlist') or not self.playlist:
        return False

    if not hasattr(self, 'current_song') or self.current_song is None:
        return False

    try:
        current_index = self.playlist.index(self.current_song)
        if current_index > 0:
            self.current_song = self.playlist[current_index - 1]
            return True
        else:
            return False
    except ValueError:
        return False

