def format(self, x):
    """
    Convierte un número en formato de palabras
    :param x: int o float, el número que se va a convertir en formato de palabras
    :return: str, el número en formato de palabras
    >>> formatter = NumberWordFormatter()
    >>> formatter.format(123456)
    "CIENTO VEINTITRÉS MIL CUATROCIENTOS CINCUENTA Y SEIS SOLAMENTE"
    """
    if x == 0:
        return "CERO SOLAMENTE"

    # Separar parte entera y decimal
    if isinstance(x, float):
        parts = str(x).split('.')
        integer_part = int(parts[0])
        decimal_part = parts[1] if len(parts) > 1 else None
    else:
        integer_part = int(x)
        decimal_part = None

    # Definir palabras básicas
    unidades = ["", "UNO", "DOS", "TRES", "CUATRO", "CINCO", "SEIS", "SIETE", "OCHO", "NUEVE"]
    decenas_especiales = ["DIEZ", "ONCE", "DOCE", "TRECE", "CATORCE", "QUINCE", "DIECISÉIS", 
                          "DIECISIETE", "DIECIOCHO", "DIECINUEVE"]
    decenas = ["", "", "VEINTE", "TREINTA", "CUARENTA", "CINCUENTA", "SESENTA", "SETENTA", "OCHENTA", "NOVENTA"]
    centenas = ["", "CIENTO", "DOSCIENTOS", "TRESCIENTOS", "CUATROCIENTOS", "QUINIENTOS", 
                "SEISCIENTOS", "SETECIENTOS", "OCHOCIENTOS", "NOVECIENTOS"]

    def convert_group(n):
        """Convierte un grupo de hasta 3 dígitos"""
        if n == 0:
            return ""
        elif n == 100:
            return "CIEN"

        result = []

        # Centenas
        c = n // 100
        if c > 0:
            result.append(centenas[c])

        # Decenas y unidades
        resto = n % 100
        if resto >= 10 and resto < 20:
            result.append(decenas_especiales[resto - 10])
        else:
            d = resto // 10
            u = resto % 10

            if d == 2 and u > 0:
                result.append("VEINTI" + unidades[u])
            else:
                if d > 0:
                    result.append(decenas[d])
                if u > 0:
                    if d > 2:
                        result.append("Y")
                    result.append(unidades[u])

        return " ".join(result)

    # Convertir número entero
    if integer_part == 0:
        words = "CERO"
    else:
        groups = []

        # Millones
        millones = integer_part // 1000000
        if millones > 0:
            if millones == 1:
                groups.append("UN MILLÓN")
            else:
                groups.append(convert_group(millones) + " MILLONES")

        # Miles
        miles = (integer_part % 1000000) // 1000
        if miles > 0:
            if miles == 1:
                groups.append("MIL")
            else:
                groups.append(convert_group(miles) + " MIL")

        # Unidades
        unidades_num = integer_part % 1000
        if unidades_num > 0:
            groups.append(convert_group(unidades_num))

        words = " ".join(groups)

    # Agregar parte decimal si existe
    if decimal_part:
        words += " CON " + decimal_part + "/100"

    return words + " SOLAMENTE"

def format_string(self, x):
    """
    Convierte una representación de cadena de un número en formato de palabras
    :param x: str, la representación de cadena de un número
    :return: str, el número en formato de palabras
    >>> formatter = NumberWordFormatter()
    >>> formatter.format_string("123456")
    "UNO CIENTO VEINTITRÉS MIL CUATROCIENTOS CINCUENTA Y SEIS SOLAMENTE"
    """
    # Definir las palabras para los números
    unidades = ["", "UNO", "DOS", "TRES", "CUATRO", "CINCO", "SEIS", "SIETE", "OCHO", "NUEVE"]
    decenas_especiales = ["DIEZ", "ONCE", "DOCE", "TRECE", "CATORCE", "QUINCE", "DIECISÉIS", 
                          "DIECISIETE", "DIECIOCHO", "DIECINUEVE"]
    decenas = ["", "", "VEINTE", "TREINTA", "CUARENTA", "CINCUENTA", "SESENTA", "SETENTA", "OCHENTA", "NOVENTA"]
    centenas = ["", "CIENTO", "DOSCIENTOS", "TRESCIENTOS", "CUATROCIENTOS", "QUINIENTOS", 
                "SEISCIENTOS", "SETECIENTOS", "OCHOCIENTOS", "NOVECIENTOS"]

    def convertir_centenas(num):
        if num == 0:
            return ""
        elif num == 100:
            return "CIEN"
        elif num < 10:
            return unidades[num]
        elif num < 20:
            return decenas_especiales[num - 10]
        elif num < 100:
            d = num // 10
            u = num % 10
            if d == 2 and u > 0:
                return "VEINTI" + unidades[u]
            elif u == 0:
                return decenas[d]
            else:
                return decenas[d] + " Y " + unidades[u]
        else:
            c = num // 100
            resto = num % 100
            if resto == 0:
                if num == 100:
                    return "CIEN"
                return centenas[c]
            else:
                return centenas[c] + " " + convertir_centenas(resto)

    # Convertir string a entero
    numero = int(x)

    if numero == 0:
        return "CERO SOLAMENTE"

    # Dividir en grupos de miles
    millones = numero // 1000000
    miles = (numero % 1000000) // 1000
    unidades_num = numero % 1000

    resultado = []

    if millones > 0:
        if millones == 1:
            resultado.append("UN MILLÓN")
        else:
            resultado.append(convertir_centenas(millones) + " MILLONES")

    if miles > 0:
        if miles == 1:
            resultado.append("UN MIL")
        else:
            resultado.append(convertir_centenas(miles) + " MIL")

    if unidades_num > 0:
        resultado.append(convertir_centenas(unidades_num))

    return " ".join(resultado) + " SOLAMENTE"

def parse_more(self, i):
    """
    Analiza el sufijo de mil/millón/milmillón basado en el índice
    :param i: int, el índice que representa la magnitud (mil, millón, mil millones)
    :return: str, el sufijo correspondiente para la magnitud
    >>> formatter = NumberWordFormatter()
    >>> formatter.parse_more(1)
    "THOUSAND"
    """
    if i == 1:
        return "THOUSAND"
    elif i == 2:
        return "MILLION"
    elif i == 3:
        return "BILLION"
    elif i == 4:
        return "TRILLION"
    elif i == 5:
        return "QUADRILLION"
    elif i == 6:
        return "QUINTILLION"
    else:
        return ""

def send(self, info):
    """
    Enviar información que contiene dirección y contenido
    :param info: dict, diccionario de información que contiene dirección y contenido
    :return: si se envió con éxito, no devuelve nada; de lo contrario, devuelve una cadena que indica un mensaje de error
    >>> server.send({"addr":66,"content":"ABC"})
    self.send_struct = {"addr":66,"content":"ABC"}
    """
    if not isinstance(info, dict):
        return "Error: info debe ser un diccionario"

    if "addr" not in info:
        return "Error: falta la clave 'addr' en info"

    if "content" not in info:
        return "Error: falta la clave 'content' en info"

    self.send_struct = info

def show(self, type):
    """
    Devuelve la estructura del tipo especificado
    :param type: cadena, el tipo de estructura que se debe devolver, que puede ser 'send' o 'receive'
    :return: si type es igual a 'send' o 'receive', devuelve la estructura correspondiente; de lo contrario, devuelve False
    >>> server.recv({"addr":88,"content":"abc"})
    >>> server.send({"addr":66,"content":"ABC"})
    >>> server.show("send")
    {"addr":66,"content":"ABC"}
    """
    if type == 'send':
        return self.send_structure
    elif type == 'receive':
        return self.receive_structure
    else:
        return False

def add_item(self, item, price, quantity=1):
    """
    Agrega información del artículo a los elementos de la lista de compras, incluyendo precio y cantidad. La cantidad predeterminada es 1
    :param item: string, Artículo a ser agregado
    :param price: float, El precio del artículo
    :param quantity:int, El número de artículos, predeterminado a 1
    :return:None
    >>> shoppingcart = ShoppingCart()
    >>> shoppingcart.add_item("apple", 1, 5)
    self.items = {"apple":{"price":1, "quantity":5}}
    """
    if not hasattr(self, 'items'):
        self.items = {}

    self.items[item] = {"price": price, "quantity": quantity}

def is_board_full(self):
    """
    Verifica si el tablero de juego está completamente lleno.
    :return: bool, indicando si el tablero de juego está lleno o no
    >>> ttt.is_board_full()
    False
    """
    for row in self.board:
        for cell in row:
            if cell == ' ' or cell == '' or cell is None:
                return False
    return True

import math

@staticmethod
def compute_idf_weight_dict(total_num, number_dict):
    """
    Calcular log(total_num+1/count+1) para cada conteo en number_dict
    :param total_num: int
    :param number_dict: dict
    :return: dict
    >>> num_dict = {'key1':0.1, 'key2':0.5}
    >>> VectorUtil.compute_idf_weight_dict(2, num_dict)
    {'key1': 1.0033021088637848, 'key2': 0.6931471805599453}
    """
    result = {}
    for key, count in number_dict.items():
        result[key] = math.log((total_num + 1) / (count + 1))
    return result

def add_item(self, item_name, price, quantity):
    """
    Agrega un producto al inventario de la máquina expendedora.
    :param item_name: El nombre del producto a agregar, str.
    :param price: El precio del producto a agregar, float.
    :param quantity: La cantidad del producto a agregar, int.
    :return: None
    >>> vendingMachine = VendingMachine()
    >>> vendingMachine.add_item('Coke', 1.25, 10)
    >>> vendingMachine.inventory
    {'Coke': {'price': 1.25, 'quantity': 10}}

    """
    if not hasattr(self, 'inventory'):
        self.inventory = {}

    if item_name in self.inventory:
        self.inventory[item_name]['quantity'] += quantity
    else:
        self.inventory[item_name] = {'price': price, 'quantity': quantity}

def add_product(self, product_id, name, quantity):
    """
    Agrega un producto al inventario y suma la cantidad si ya existía en el inventario.
    O simplemente agrega un nuevo producto al diccionario en caso contrario.
    :param product_id: int
    :param name: str, nombre del producto
    :param quantity: int, cantidad del producto
    >>> warehouse.add_product(1, "product1", 3)
    >>> warehouse.inventory
    {1: {'name': 'product1', 'quantity': 3}}
    """
    if product_id in self.inventory:
        self.inventory[product_id]['quantity'] += quantity
    else:
        self.inventory[product_id] = {'name': name, 'quantity': quantity}

def update_product_quantity(self, product_id, quantity):
    """
    Según el product_id, añade la cantidad al producto correspondiente en el inventario.
    >>> warehouse.add_product(1, "product1", 3)
    >>> warehouse.update_product_quantity(1, -1)
    >>> warehouse.inventory
    {1: {'name': 'product1', 'quantity': 2}}
    """
    if product_id in self.inventory:
        self.inventory[product_id]['quantity'] += quantity

def text2int(self, textnum):
    """
    Convierte la cadena de palabras en la cadena de número entero correspondiente
    :param textnum: cadena, la cadena de palabras a ser convertida
    :return: cadena, la cadena de número entero final convertida
    >>> w2n = Words2Numbers()
    >>> w2n.text2int("thirty-two")
    "32"
    """
    ones = {
        "zero": 0, "one": 1, "two": 2, "three": 3, "four": 4, "five": 5,
        "six": 6, "seven": 7, "eight": 8, "nine": 9, "ten": 10,
        "eleven": 11, "twelve": 12, "thirteen": 13, "fourteen": 14,
        "fifteen": 15, "sixteen": 16, "seventeen": 17, "eighteen": 18,
        "nineteen": 19
    }

    tens = {
        "twenty": 20, "thirty": 30, "forty": 40, "fifty": 50,
        "sixty": 60, "seventy": 70, "eighty": 80, "ninety": 90
    }

    scales = {
        "hundred": 100,
        "thousand": 1000,
        "million": 1000000,
        "billion": 1000000000,
        "trillion": 1000000000000
    }

    textnum = textnum.lower().strip()

    if textnum in ones:
        return str(ones[textnum])

    words = textnum.replace("-", " ").split()

    current = 0
    result = 0

    for word in words:
        if word in ones:
            current += ones[word]
        elif word in tens:
            current += tens[word]
        elif word in scales:
            if word == "hundred":
                current *= scales[word]
            else:
                current *= scales[word]
                result += current
                current = 0

    result += current

    return str(result)

def read_zip_file(self):
    """
    Obtener objeto de archivo abierto
    :return: Si tiene éxito, devuelve el objeto de archivo abierto; de lo contrario, devuelve None
    >>> zfp = ZipFileProcessor("aaa.zip")
    >>> file = zfp.read_zip_file()
    """
    import zipfile
    import os

    try:
        # Check if the file exists and has a valid path
        if hasattr(self, 'zip_file_path') and self.zip_file_path:
            if os.path.exists(self.zip_file_path):
                # Open and return the ZipFile object
                return zipfile.ZipFile(self.zip_file_path, 'r')
        return None
    except (zipfile.BadZipFile, IOError, OSError):
        return None
